var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"오래전 아마존 유역 원주민에게는 어떤 전설이 전해져 왔다.","JPN":"古くからアマゾン流域の先住民には、とある伝説が語り継がれてきた。","ENG":"Long ago, a legend was passed down among the indigenous people of the Amazon basin.","TWN":"很久以前，在亞馬遜流域的原住民之間，流傳著一則傳說。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"그것은 어느 종말에 관한 예언.","JPN":"それは終末に関する予言。","ENG":"It spoke of a prophecy of the world's end.","TWN":"那是關於某個末日的預言。  "},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"찬란하게 빛나는 태양이 나무뿌리에 가려, 그 빛을 잃어버리게 될 때.","JPN":"燦々と輝く太陽が木の根に隠れ、その光を失う時。","ENG":"When the radiant sun is veiled by roots, its light fading away...","TWN":"當璀璨耀眼的陽光被樹根遮蔽而失去光芒之時，"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"하늘이 갈라지며 땅과 구름이 맞닿는 곳, 어딘가 황금의 도시가 모습을 드러내고.","JPN":"天が切り裂かれ、地と雲が交わる場所、そのどこかに黄金の都市が姿を現し、","ENG":"The heavens will split open, and where earth and cloud meet, a golden city will appear.","TWN":"天空將會裂開，在大地與雲彩交會的地方，黃金城將現身。  "},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"그곳, 황금향이 남긴 유산이 수많은 이들을 구하게 될 것이라는 이야기.","JPN":"かの地、黄金郷が残した遺産が多くの者を救うであろうという伝説だ。","ENG":"There, the Golden Vale's Legacy will save countless lives.","TWN":"據說，黃金城留下的寶藏，將拯救無數的人。  "},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"노스트라다무스의 지구 종말론, 마야족의 달력설, 시빌라의 예언서…….","JPN":"ノストラダムスの人類滅亡論、マヤ族の暦にまつわる話、シビュラの書……","ENG":"Nostradamus' doomsday prophecies, the Mayan calendar, the Sibyl's oracles...","TWN":"諾斯特拉達穆斯的地球末日論、馬雅曆法的末日說、西比拉的預言書……  "},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"세계 종말에 관한 예언은 어느 시대에나 존재했고 또한 부질없이 사라졌으니.","JPN":"世界終末に関する予言はどの時代にも存在し、その度に虚しく消えていった。","ENG":"Every age has had its own visions of the world's end, and every one of them faded into nothing.","TWN":"關於世界末日的預言，在任何時代都曾存在，最後也都悄然消逝。  "},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"황금향에 관한 전설 또한 특별히 그보다 낫다고 말할 수는 없었다.","JPN":"黄金郷の伝説もまた然り。それらの予言よりもましだとは言えなかった。","ENG":"The legend of the Golden Vale was no different or better than the rest.","TWN":"黃金城的傳說，也無法說比這些預言更加可信。  "},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"늘 그렇듯, 사료는 빈약했고 현실적인 문제는 넘쳐났으니까.","JPN":"ご多分に漏れず史料は乏しく、現実的な問題は山積みだった。","ENG":"As always, the records were scarce, while real-world problems were endless.","TWN":"一如往常，史料稀少，現世問題層出不窮。  "},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"그럼에도…….","JPN":"にもかかわらず……","ENG":"And yet...","TWN":"就算是這樣……  "},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"그럼에도 나는 무언가에 홀린 듯, 계속해서 황금향을 쫓고 있었다.","JPN":"それにもかかわらず、ワシは何かに取り憑かれたように、黄金郷を追い続けていた。","ENG":"And yet, as if bewitched, I kept chasing after the Golden Vale.","TWN":"就算是這樣，我依然像是著了魔一般，不斷追尋著黃金城。  "},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"그렇게 속절없이 세월은 흐르고…….","JPN":"そうやって無情にも時は流れ……","ENG":"So the years slipped by in vain...","TWN":"歲月在不知不覺中流逝……  "},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"narration","speaker":null,"text":{"KOREA":"수많은 예언이 비웃음거리가 되어, 하나둘씩 역사의 뒤안길로 사라져갈 무렵.","JPN":"数多の予言が夢物語となり、徐々に歴史の中に埋もれていく頃。","ENG":"By the time most prophecies had become laughingstocks and faded into history...","TWN":"無數預言淪為笑柄，逐一被歷史的洪流吞沒之時，"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>관리 실패</color>가 일어나, 세계 각지에 대균열이 발생하고.","JPN":"<color=#ffd34c>管理失敗</color>により世界各地に大亀裂が発生し、","ENG":"The <color=#ffd34c>Administration Failure</color> struck, and the Grand Dimension Crevice erupted across the world.","TWN":"發生<color=#ffd34c>管理失敗</color>，世界各地出現大峽谷。  "},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"아마존 일대는 하늘이 갈라지며, 땅이 부유하기 시작했다.","JPN":"アマゾン一帯は天が切り裂かれ、地面は浮遊した。","ENG":"Here in the Amazon, the sky split apart, and the land itself began to float.","TWN":"亞馬遜一帶的天空裂開，大地開始漂浮。  "},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"narration","speaker":null,"text":{"KOREA":"그로부터 20여 년 뒤…….","JPN":"それから20年後……","ENG":"And twenty years later...","TWN":"20年後……  "},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"사람들은 구름과 땅이 맞닿은 이곳을 <color=#ffd34c>천공섬</color>이라고 불렀고.","JPN":"人々は雲と地が交わるここを<color=#ffd34c>天空島</color>と呼ぶようになり……","ENG":"People came to call this place, where cloud and earth touched, the <color=#ffd34c>floating island</color>.","TWN":"人們稱雲與地相接的這片土地為<color=#ffd34c>天空島</color>。  "},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"나는 여전히 황금향의 유산을 쫓고 있었다.","JPN":"ワシは依然として黄金郷の遺産を追いかけている。","ENG":"And I was still pursuing the Golden Vale's Legacy.","TWN":"而我，依然在追尋黃金城的寶藏。  "},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>캄파멘토</color>\\n해발 고도 약 10,000m 지점 <color=#ffd34c>태양이 떠오르는 천공섬</color>","JPN":"管理局直轄都市<color=#ffd34c>カンパメント</color>\\n標高約10,000m地点、<color=#ffd34c>太陽が昇る天空島</color>","ENG":"[[","TWN":"管理局直轄市<color=#ffd34c>坎帕門托</color>\\n海拔約10,000公尺處的 <color=#ffd34c>日出東方天空島</color>","SCN":"管理局直属城市<color=#ffd34c>坎帕门托</color>\\n海拔高度约10,000米处<color=#ffd34c>太阳升起的天空岛</color>","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_QM","text":{"KOREA":"침식체 토벌 확인. 에어리어 감마, 정화 작전 완료.","JPN":"侵食体の討伐を確認。エリアガンマ、浄化作戦完了。","ENG":"C.O. extermination confirmed. Area Gamma, purification op complete.","TWN":"已確認殲滅侵蝕體。伽瑪區域，淨化作戰完成。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_QM","text":{"KOREA":"제가 자리를 비운 그새를 못 참고 또 탐험대를 소집해서 천공섬을 방문하셨더군요.","JPN":"私が留守の間、さっそく探検隊を招集して天空島を訪ねたそうですね。","ENG":"The moment I was away, you couldn't resist calling another expedition to the floating island.","TWN":"我才剛離開一下，你就又忍不住召集探險隊前往天空島是吧？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_QM","text":{"KOREA":"어디 다치신 데는 없습니까, 시니어 칸?","JPN":"お怪我はありませんか？　シニア・カン。","ENG":"You're not hurt, are you, Senior Khan?","TWN":"沒受傷吧，Senior？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"이야~ 역시 공인 카운터 제도는 편리하단 말이지~?","JPN":"いやぁ～、やはり公認カウンター制度は便利なものじゃのう。","ENG":"Heh, gotta admit. The Official Counter system is convenient, isn't it?","TWN":"哇～公認制裁者制度果然很便利呢～ "},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"1급 탐험대가 발이 묶여 쩔쩔매던 대형 침식체 무리를 호출 한 번으로 해결할 수 있다니.","JPN":"1級探検隊も太刀打ちできなかった大型侵食体の群れを、呼び出し1回で解決できるとは。","ENG":"Who would've thought a single summon could wipe out a swarm of C.O.s that even a Class 1 expedition team was helpless against?","TWN":"連一級探險隊都束手無策的一大群侵蝕體，只要一通電話就能解決！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"매번 노인네 뒤치다꺼리하느라 자네가 고생이 많아, 웨이드.","JPN":"この老いぼれのせいで、毎回手間をかけるのう、ウェイド。","ENG":"You've had a rough time cleaning up after this old man, Wade.","TWN":"每次都得幫我這個老傢伙收拾善後，真是辛苦你啦，韋德。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"칭찬은 됐습니다. 시니어를 지키는 게, 공인 카운터의 최우선 사항이니까요.","JPN":"よしてください。シニアを守ることが、公認カウンターの最優先事項なのですから。","ENG":"No need for compliments. Protecting a Senior is an Official Counter's top priority.","TWN":"這些話就免了。保護前輩，就是公認制裁者的首要任務。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"물론, 최우선 사항을 남발하는 악질 시니어가 있다는 건, 시스템의 헛점이겠지만요.","JPN":"悪質なシニアは最優先事項を悪用しまくれるという点は、システムの穴ですがね。","ENG":"Though the fact that some Seniors abuse that priority... says a lot about the system's flaws.","TWN":"不過，也因為有像你這樣濫用體制的人，才讓系統變得有漏洞吧。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"노스트라다무스의 지구 종말론, 마야족의 달력설, 시빌라의 예언서…….","JPN":"ノストラダムスの人類滅亡論、マヤ族の暦にまつわる話、シビュラの書……","ENG":"Nostradamus' doomsday prophecies, the Mayan calendar, the Sibyl's oracles...","TWN":"諾斯特拉達穆斯的地球末日論、馬雅曆法的末日說、西比拉的預言書……  "},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};